function present(value) {
  return value !== undefined && value !== null && String(value).trim() !== '';
}

function cleanPhone(value) {
  if (!present(value)) return '';
  const text = String(value).trim();
  if (text.startsWith('+')) return '+' + text.slice(1).replace(/\D/g, '');
  return text.replace(/[^\d+]/g, '');
}

function lineValue(text, labelPattern) {
  const pattern = new RegExp(`^\\s*(?:${labelPattern})\\s*[:=]\\s*(.+)$`, 'im');
  const match = String(text || '').match(pattern);
  return match ? match[1].trim() : '';
}

function formatDateTime(value) {
  if (!present(value)) return 'your scheduled time';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

const event = $json;
const text = [event.summary, event.description, event.location].filter(present).join('\n');
const explicitPhone = lineValue(text, 'Phone|Tel|Mobile|SMS');
const fallbackPhone = (text.match(/\+?[0-9][0-9\s().-]{7,}/) || [])[0] || '';
const phone = cleanPhone(explicitPhone || fallbackPhone);
const consentText = lineValue(text, 'SMS consent|smsConsent|SMS opt in|sms_opt_in');
const hasConsent = ['yes', 'true', '1', 'subscribed', 'ok'].includes(String(consentText).trim().toLowerCase());
const optedOut = /\b(no sms|sms opt out|unsubscribe|do not text|stop)\b/i.test(text);
const customerName = lineValue(text, 'Name|Customer|Client') || 'there';
const start = event.start?.dateTime || event.start?.date || '';
const appointmentTime = formatDateTime(start);
const service = event.summary || 'your appointment';
const location = present(event.location) ? ` at ${event.location}` : '';
const message = `Hi ${customerName}, reminder: ${service} is scheduled for ${appointmentTime}${location}. Reply STOP to opt out.`;
const eligible = Boolean(phone && hasConsent && !optedOut);

return [{
  json: {
    eligible,
    skipReason: eligible ? '' : 'Missing phone, SMS consent, or customer has opted out',
    phone,
    message: message.length > 320 ? message.slice(0, 317) + '...' : message,
    customerName,
    appointmentTime,
    service,
    location: event.location || '',
    eventId: event.id || '',
  },
}];
